// translated_0.cl - OpenCL SRAD kernels

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

__kernel void srad_kernel(
    float lambda,
    int Nr,
    int Nc,
    long Ne,
    const int* d_iN,
    const int* d_iS,
    const int* d_jE,
    const int* d_jW,
    float* d_dN,
    float* d_dS,
    float* d_dW,
    float* d_dE,
    float* d_c,
    float* d_I,
    float q0sqr
)
{
    int idx = get_global_id(0);

    if (idx < Ne) {
        float Jc = d_I[idx];

        int iN_idx = d_iN[idx];
        int iS_idx = d_iS[idx];
        int jW_idx = d_jW[idx];
        int jE_idx = d_jE[idx];

        d_dN[idx] = d_I[iN_idx] - Jc;
        d_dS[idx] = d_I[iS_idx] - Jc;
        d_dW[idx] = d_I[jW_idx] - Jc;
        d_dE[idx] = d_I[jE_idx] - Jc;

        float G2 = (d_dN[idx]*d_dN[idx] + d_dS[idx]*d_dS[idx] + 
                   d_dW[idx]*d_dW[idx] + d_dE[idx]*d_dE[idx]) / (Jc*Jc);

        float L = (d_dN[idx] + d_dS[idx] + d_dW[idx] + d_dE[idx]) / Jc;

        float num = (0.5f*G2) - ((1.0f/16.0f)*(L*L));
        float den = 1.0f + (0.25f*L);
        float qsqr = num/(den*den);

        den = (qsqr-q0sqr) / (q0sqr * (1.0f+q0sqr));
        float c = 1.0f / (1.0f+den);

        if (c < 0.0f) c = 0.0f;
        else if (c > 1.0f) c = 1.0f;

        d_c[idx] = c;
    }
}

__kernel void srad2_kernel(
    float lambda,
    int Nr,
    int Nc,
    long Ne,
    const int* d_iN,
    const int* d_iS,
    const int* d_jE,
    const int* d_jW,
    float* d_dN,
    float* d_dS,
    float* d_dW,
    float* d_dE,
    float* d_c,
    float* d_I
)
{
    int idx = get_global_id(0);

    if (idx < Ne) {
        float cN = d_c[idx];
        float cS = d_c[d_iS[idx]];
        float cW = d_c[idx];
        float cE = d_c[d_jE[idx]];

        float D = cN * d_dN[idx] + cS * d_dS[idx] + 
                  cW * d_dW[idx] + cE * d_dE[idx];

        d_I[idx] = d_I[idx] + 0.25f*lambda*D;
    }
}
